for size in range(1, n):
    for S in combinations(range(n), size):
        S_set = set(S)
        cut_arcs = [a for a in range(m) if tail[a] in S_set and head[a] not in S_set]
        K_S = [k for k in range(K) if O[k] in S_set and D[k] not in S_set]
        if not K_S or not cut_arcs:
            continue
        D_B = sum(d[k] for k in K_S)
        model.addConstr(
            gp.quicksum(min(u[a], D_B) * y[a] for a in cut_arcs) >= D_B
        )
